INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1000001, "2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 1, "カリン", 190805, 62, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", -416.5, 2, 1, 1, 3.414);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1000002, "2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 2, "カリン", 190805, 62, "ミッションをクリアして、\n報酬をゲットしましょう！", -416.5, 2, 1, 1, 3.099);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1000003, "2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 3, "カリン", 190805, 63, "受け取ることができる\n報酬があるようです\n確認してみてください", -416.5, 2, 1, 1, 2.801);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1000004, "2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 4, "カリン", 190805, 63, "報酬がもらえますよ！\nチェックしてみてください", -416.5, 2, 1, 2, 0.0);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1000005, "2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 5, "カリン", 190805, 64, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", -363.0, 1, 1, 2, 2.12);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1000006, "2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 6, "カリン", 190805, 64, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", -363.0, 2, 1, 1, 1.68);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1000007, "2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 7, "カリン", 190805, 64, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", -363.0, 1, 1, 2, 2.33);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020101, "2030/01/01 14:59:59", "2025/01/31 12:00:00", -6.0, 101, "ラビリスタ", 133701, 61, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", -285.0, 7, 10201, 3, 5.18);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020102, "2030/01/01 14:59:59", "2025/01/31 12:00:00", -2.0, 201, "クリスティーナ", 133901, 61, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", -285.0, 2, 10201, 1, 8.77);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020103, "2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 301, "ネネカ", 133801, 61, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", -285.0, 1, 10201, 6, 15.5);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020201, "2030/01/01 14:59:59", "2025/02/28 12:00:00", 0.0, 101, "ランファ", 134301, 61, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", -285.0, 5, 10202, 2, 9.061);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020202, "2030/01/01 14:59:59", "2025/02/28 12:00:00", 0.0, 201, "チカ", 134401, 61, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", -285.0, 2, 10202, 1, 7.699);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020301, "2030/01/01 14:59:59", "2025/03/31 12:00:00", 0.0, 101, "アオイ", 134601, 61, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", -285.0, 2, 10203, 1, 8.595);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020302, "2030/01/01 14:59:59", "2025/03/31 12:00:00", 0.0, 201, "クローチェ", 134501, 61, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", -285.0, 2, 10203, 1, 7.758);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020401, "2030/01/01 14:59:59", "2025/04/30 12:00:00", 0.0, 101, "ルイズマリー", 132302, 61, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", -285.0, 6, 10204, 2, 7.0);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020402, "2030/01/01 14:59:59", "2025/04/30 12:00:00", 0.0, 201, "イロハ", 132402, 61, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", -285.0, 2, 10204, 1, 7.904);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020403, "2030/01/01 14:59:59", "2025/04/30 12:00:00", 0.0, 301, "ソノ", 132502, 61, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", -285.0, 2, 10204, 4, 8.487);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020502, "2030/01/01 14:59:59", "2025/05/31 12:00:00", 0.0, 101, "カノン", 134901, 61, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", -285.0, 2, 10205, 1, 8.763);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020503, "2030/01/01 14:59:59", "2025/05/31 12:00:00", 0.0, 201, "ツムギ", 134801, 61, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", -285.0, 3, 10205, 1, 6.417);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020601, "2030/01/01 14:59:59", "2025/06/30 12:00:00", 0.0, 101, "エリス", 135001, 61, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", -285.0, 7, 10206, 3, 10.335);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020602, "2030/01/01 14:59:59", "2025/06/30 12:00:00", 0.0, 201, "シェフィ", 135101, 61, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", -285.0, 4, 10206, 2, 6.281);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020603, "2030/01/01 14:59:59", "2025/06/30 12:00:00", 0.0, 301, "プレシア", 135201, 61, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", -285.0, 2, 10206, 1, 12.244);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020701, "2030/01/01 14:59:59", "2025/07/31 12:00:00", 0.0, 101, "クリア", 135301, 61, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", -285.0, 8, 10207, 2, 6.339);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020702, "2030/01/01 14:59:59", "2025/07/31 12:00:00", 0.0, 201, "アネモネ", 135401, 61, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", -285.0, 9, 10207, 7, 8.184);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020801, "2030/01/01 14:59:59", "2025/08/31 12:00:00", 0.0, 101, "アイラ", 129101, 61, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", -285.0, 2, 10208, 9, 3.906);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020802, "2030/01/01 14:59:59", "2025/08/31 12:00:00", 0.0, 201, "シナツ", 129201, 61, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", -285.0, 2, 10208, 1, 14.465);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020803, "2030/01/01 14:59:59", "2025/08/31 12:00:00", 0.0, 301, "ヒヨリ", 100101, 61, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", -285.0, 3, 10208, 4, 8.662);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020804, "2030/01/01 14:59:59", "2025/08/31 12:00:00", 0.0, 401, "レイ", 100301, 61, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", -285.0, 3, 10208, 1, 10.915);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020901, "2030/01/01 14:59:59", "2025/09/30 12:00:00", 0.0, 101, "ユキノ", 135802, 61, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", -285.0, 7, 10209, 1, 6.042);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020902, "2030/01/01 14:59:59", "2025/09/30 12:00:00", 0.0, 201, "サツキ", 135903, 61, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", -285.0, 1, 10209, 4, 9.402);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1020903, "2030/01/01 14:59:59", "2025/09/30 12:00:00", 0.0, 301, "ルルィ", 136902, 61, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", -285.0, 1, 10209, 8, 8.16);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021001, "2030/01/01 14:59:59", "2025/10/31 12:00:00", 0.0, 101, "カスミ", 137401, 61, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", -285.0, 2, 10210, 3, 5.0);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021002, "2030/01/01 14:59:59", "2025/10/31 12:00:00", 0.0, 201, "アラクネ", 136001, 61, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", -285.0, 1, 10210, 4, 8.12);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021003, "2030/01/01 14:59:59", "2025/10/31 12:00:00", 0.0, 301, "ナーナ", 136202, 61, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", -285.0, 2, 10210, 4, 6.386);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021101, "2030/01/01 14:59:59", "2025/11/30 12:00:00", 0.0, 101, "ユイ", 136402, 61, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", -285.0, 4, 10211, 3, 7.438);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021102, "2030/01/01 14:59:59", "2025/11/30 12:00:00", 0.0, 201, "ミソラ", 136302, 61, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", -285.0, 5, 10211, 1, 8.35);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021201, "2030/01/01 14:59:59", "2025/12/31 12:00:00", 0.0, 101, "シズル", 136501, 61, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", -285.0, 2, 10212, 1, 5.0);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021202, "2030/01/01 14:59:59", "2025/12/31 12:00:00", 0.0, 201, "リノ", 137902, 61, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", -285.0, 2, 10212, 1, 5.25);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021203, "2030/01/01 14:59:59", "2025/12/31 12:00:00", 0.0, 301, "ラビリスタ", 106801, 61, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", -285.0, 2, 10212, 1, 7.5);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021301, "2030/01/01 14:59:59", "2026/01/31 12:00:00", 0.0, 101, "ライラエル", 126501, 61, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", -285.0, 2, 10213, 1, 8.204);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021302, "2030/01/01 14:59:59", "2026/01/31 12:00:00", 0.0, 201, "ネフィ＝ネラ", 129701, 61, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", -285.0, 2, 10213, 1, 7.176);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021303, "2030/01/01 14:59:59", "2026/01/31 12:00:00", 0.0, 301, "ヴァイオレット", 133101, 61, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", -285.0, 5, 10213, 1, 8.602);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021304, "2030/01/01 14:59:59", "2026/02/06 12:00:00", 0.0, 102, "ライラエル", 138101, 61, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", -285.0, 3, 10213, 1, 10.14);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021305, "2030/01/01 14:59:59", "2026/02/06 12:00:00", 0.0, 202, "ネフィ＝ネラ", 138201, 61, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", -285.0, 7, 10213, 1, 10.152);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021306, "2030/01/01 14:59:59", "2026/02/06 12:00:00", 0.0, 302, "ヴァイオレット", 138001, 61, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", -285.0, 3, 10213, 4, 9.688);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021307, "2030/01/01 14:59:59", "2026/02/12 12:00:00", 0.0, 401, "ペコリーヌ", 138301, 61, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", -285.0, 1, 10213, 2, 5.928);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021401, "2030/01/01 14:59:59", "2026/02/28 12:00:00", 0.0, 101, "ワカナ", 138702, 61, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", -285.0, 2, 10214, 4, 9.19);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1021402, "2030/01/01 14:59:59", "2026/02/28 12:00:00", 0.0, 201, "シオリ", 138802, 61, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", -285.0, 3, 10214, 1, 8.724);
